var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"......잠깐.","JPN":"……お待ちください。","ENG":"Wait.","TWN":"……等等。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"부서진 네임리스 원의 고치 안에서 침식파와는 다른 이질적인 에너지가 느껴집니다!","JPN":"壊れたネームレスワンの繭の中から、侵食波とは違う異質なエネルギーが感じられます！","ENG":"I can feel an energy inside the broken cocoon! It's different from the Corruption ray!","TWN":"在無名1破碎的卵囊中，我感受到了與侵蝕波不同的其他能量反應！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"위험할지도 모르니 물러서세요, 부사령관님!","JPN":"危険かもしれません。下がってください、副司令官！","ENG":"Stay back, Deputy Commander. It might be dangerous!","TWN":"可能會有危險。請先退後，副司令官大人！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연...... 듣던대로 아주 인상적인 방식이네요.","JPN":"なるほど……聞いていたとおり、とても印象的なやり方ですね。","ENG":"Hmm... It's an interesting method, like I heard.","TWN":"果然…… 就如同傳說的那樣，真是令人印象深刻的方式。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"뭐라고? 넌 저 고치 안에 뭐가 있는지 알고 있는 건가?","JPN":"何だと？　お前はあの繭の中に何があるのか知ってるのか？","ENG":"What? Do you know what's inside that cocoon?","TWN":"你說什麼？你知道那個卵囊裡有什麼嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아니요, 사실 정확히는 모릅니다.","JPN":"いいえ、正確にはわかりません。","ENG":"No, not exactly.","TWN":"不，我其實並不是很清楚。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그저 아주 대단하신 분께 대강의 이야기를 전해 들었을 뿐이죠.","JPN":"ただ、とてもすごい方から、大体の話を聞いただけです。","ENG":"But I heard a rough story from a remarkable person.","TWN":"我只是聽一位很偉大的人講述過大致的故事。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대단하신 분? 네가 그렇게 부를만한 사람이 있었나?","JPN":"すごい方？　お前がそんな風に呼ぶほどの人がいるのか？","ENG":"A remarkable person? Who could it be?","TWN":"偉大的人？還能有人有資格讓你那樣稱呼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한때 제 상관이었던 분입니다.","JPN":"かつて、僕の上官だった人です。","ENG":"My former boss.","TWN":"那位是我以前的上司。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세상의 모든 슬픔을 경험한...... 아주 불쌍한 분이죠.","JPN":"この世のあらゆる悲しみを経験した……とても可哀想な方です。","ENG":"A poor soul... who has experienced all the sorrow in the world.","TWN":"經歷了世界上所有悲傷的…… 非常可憐的人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......무슨 말인지 모르겠군.","JPN":"……何を言っているんだか、さっぱりわからないな。","ENG":"I don't understand what you're talking about.","TWN":"……不知道你在說什麼。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하여간 넌 저 고치 안에서 무슨 일이 벌어지는지 짐작하고 있다는 뜻이겠지?","JPN":"とにかく、お前はあの繭の中で何が起こっているのか推測できるということだろう？","ENG":"Anyways, it means you can guess what's happening inside that cocoon, right?","TWN":"總之，意思就是你猜到那個卵囊裡到底在發生什麼，對吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 제 추측이 맞다면 저건 아마도 아주 오랜 과거로부터 온 선물일 겁니다.","JPN":"はい。僕の推測が正しければ、あれはおそらくいにしえからの贈り物です。","ENG":"Yes. If my guess is correct, it's a gift from the past.","TWN":"是的。如果我的推測正確，那可能就是從更加遙遠的從前所送來的禮物。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"선물이라고?","JPN":"贈り物だと？","ENG":"A gift?","TWN":"禮物？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래요. 네임리스 원은 애초에 저걸 전달하기 위한 살아있는 포장지였던 셈이죠.","JPN":"ええ。ネームレスワンはあれを届けるための、生きた包装紙だったのでしょう。","ENG":"Yes. The Nameless One was in fact a living package, created to deliver that gift.","TWN":"是啊。無名1從一開始就是為了送達這個禮物而活著的包裝紙而已。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 포장을 풀 <color=#ffd34c>자격</color>을 가진 자만이 <color=#ffd34c>선물</color>을 꺼낼 수 있도록 설계되어 있었던 겁니다.","JPN":"そして、その包装を開ける<color=#ffd34c>資格</color>を持つ者のみ<color=#ffd34c>プレゼント</color>を取り出せるように設計されているのでしょう。","ENG":"It was designed so that only a <color=#ffd34c>worthy</color> person could open the <color=#ffd34c>gift</color>.","TWN":"還有，為了只讓有<color=#ffd34c>資格</color>打開包裝的人取出<color=#ffd34c>禮物</color>，所以才設計成這樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"놈을 쓰러트릴 힘이 없다면, 어차피 선물을 얻게 되더라도 그걸 감당하지 못할 거란 뜻이겠죠.","JPN":"奴を倒せる力がなければ、プレゼントを手に入れたとしても扱いきれないということです。","ENG":"It probably means that if you can't handle the monster, you can't handle the gift either.","TWN":"也就是說如果沒有打敗它的力量，就算獲得禮物也無法承受。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"터무니없군. 그 5종 침식체가...... 누군가에 의해 의도적으로 보내진 거라고?","JPN":"とんでもない話だな。あの第5種侵食体が、誰かによって意図的に送られたものだと？","ENG":"You're talking nonsense. That Category 5 C.O. was sent by someone on purpose?","TWN":"真是荒謬。那5類侵蝕體是…… 被某人故意送過來的？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 짓을 벌인 이유가 고작...... 무언가를 전달하기 위해서라니.","JPN":"そんなことをした理由が、たかが……何かを届けるためだなんて。","ENG":"And whoever did it just wanted to deliver something?","TWN":"做這種事的理由僅僅…… 是為了傳達某樣東西？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대체 어째서지?!","JPN":"いったいなぜだ！？","ENG":"What the hell?","TWN":"到底為什麼？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 두 번째 질문에 대한 답은 간단합니다.","JPN":"その二つ目の疑問に対する答えは簡単です。","ENG":"The answer to the latter question is simple.","TWN":"第二個問題的答案其實很簡單。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세계선을 넘어서 무언가를 보낸다는 건 아주 어려운 일이거든요.","JPN":"世界線を越えて何かを送るということは、とても難しいことです。","ENG":"It's very, very difficult to send something to another world.","TWN":"穿越世界線送來某個東西是非常困難的事。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 선물에 어떤 가치가 있느냐에 대한 답은......","JPN":"そしてそのプレゼントにどんな価値があるのかという答えは……","ENG":"And the answer to what the gift is worth...","TWN":"那個禮物有何價值，答案就在……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래요, 직접 가서 보면 알게 되겠죠.","JPN":"そうですね。直接確かめればわかるでしょう。","ENG":"Well, we'll have to see for ourselves.","TWN":"沒錯，親自去看看就知道了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......좋다.","JPN":"……いいだろう。","ENG":"Alright.","TWN":"……好吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"가보도록 하지.","JPN":"行ってみよう。","ENG":"Let's go.","TWN":"就讓我親眼看看吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"이건......?","JPN":"これは……？","ENG":"Huh?","TWN":"這個……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"대체 뭐죠, 이 꼬마는?","JPN":"いったい何ですか、この子どもは？","ENG":"Who's this child?","TWN":"這個小鬼，到底是什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"어째서 이런 꼬마가 네임리스 원의 고치 안에......","JPN":"なぜこんな子どもがネームレスワンの繭の中に……","ENG":"What's she doing in the Nameless One's cocoon?","TWN":"為什麼這個小鬼會在無名1的卵囊裡……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이게 네가 말한 선물 이라는 건가?","JPN":"これがお前が言ったプレゼントなのか？","ENG":"Is this the gift you talked about?","TWN":"這就是你說的禮物嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"놀라운 일이긴 하지만, 이해하기가 어려운데.","JPN":"驚くべきことだが、理解しがたいな。","ENG":"It's surprising, but still incomprehensible.","TWN":"很令人吃驚，也讓人難以了解。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"......저도 놀랍군요.","JPN":"……僕も驚きました。","ENG":"...I'm surprised, too.","TWN":"……我也嚇了一跳。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한번 초월 변이 인자로 변해버린 실험체를, 일부이긴 하지만 다시 소체로 환원시킬 수 있다니.","JPN":"一度、超越変異ファクターに変わってしまった実験体を、一部ではあっても再び素体に還元させることができるとは。","ENG":"I didn't know it was possible to turn a specimen mutated by the Transcendental Mutation Factor back to its original state.","TWN":"竟然能將變成超越變異因數的實驗體重新還原成這個小小的個體，哪怕僅僅是其中一部分。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이걸 설계한 사람에겐 확실히 경의를 표할 만 하네요.","JPN":"これを設計した人には、ぜひ敬意を表したいですね。","ENG":"I'm truly in awe of the person who designed this.","TWN":"確實要向設計這個的人表達敬意。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아까부터 자꾸 알 수 없는 소리만 하는군. 조금 설명을 해주면 좋겠는데.","JPN":"先ほどからわからないことばかり言っているようだが。少し説明してもらいたい。","ENG":"I would appreciate it if you would speak in English.","TWN":"你從剛才開始就說些別人聽不懂的話。可以說明一下嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 죄송합니다. 그럼 같이 보도록 할까요?","JPN":"ハハ、すみません。それじゃあ一緒に見ましょうか？","ENG":"Hah hah, I'm sorry. Then shall we check it out together?","TWN":"哈哈，對不起。那一起來看看吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"프로젝트 테라사이드 생체 단말기.","JPN":"プロジェクト・テラサイド生体端末機。","ENG":"Project Terraside Biological Terminal.","TWN":"特拉賽德生物終端機專案。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L45_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"기동.","JPN":"起動。","ENG":"Activated.","TWN":"啟動。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_BALISADA_SKILL_LOOP"},{"id":"L46_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"자격검증 절차 완료. 데이터 전달 프로토콜 개시.","JPN":"資格検証手続き完了。データ伝達プロトコル開始。","ENG":"Verification complete. Data transfer protocol initiated.","TWN":"已完成資格驗證。開始資料傳輸協議。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"첫 번째 파일을 재생합니다.","JPN":"1つ目のファイルを再生します。","ENG":"Playing the first file.","TWN":"播放第一個檔案。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"UI_WORLDMAP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"반갑군.","JPN":"お会いできて光栄だ。","ENG":"Greetings.","TWN":"歡迎。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"당신이 누구인지는 모르겠지만 이 영상을 보고 있다는 건 내가 보낸 5종 침식체를 쓰러트렸다는 뜻이겠지.","JPN":"あなたが誰かはわからないが、この映像を見ているということは、\\n私が送った第5種侵食体を倒したということだろう。","ENG":"I don't know who you are, but if you're watching this, you must have defeated the Category 5 C.O. that I sent.","TWN":"雖然不知道你是誰，但能看到這個影片，就說明已經打倒了我送過去的5類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"우선 미증유의 적을 격퇴한 것을 축하하네.","JPN":"まず、未曾有の敵を撃退したことを称えよう。","ENG":"First of all, congratulations on defeating an unprecedented enemy.","TWN":"首先祝賀你打敗了史無前例的敵人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"그리고 자네의 세계에 이런 괴물을 보낸 것도 사과하겠다.","JPN":"そして君の世界にこんな化け物を送ってしまったことを謝罪する。","ENG":"And I'm sorry I had to send such a terrible monster to your world.","TWN":"還有對於把這種怪物送到你的世界這件事，我表示歉意。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"분명 5종 침식체와 싸우는 과정에서 많은 희생과 피해가 있었을 걸세.","JPN":"おそらく第5種侵食体と戦う過程で、多くの犠牲と被害が伴ったはずだ。","ENG":"There must've been many casualties while fighting this Category 5 C.O.","TWN":"與5類侵蝕體戰鬥的過程中，一定會有很多犧牲和傷害。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"내가 증오스럽겠지.","JPN":"私のことが憎いだろう。","ENG":"You must hate me.","TWN":"你應該很恨我吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"하지만 지금 중요한 것은 그게 아니야.","JPN":"しかし、今重要なことはそこではない。","ENG":"But that's not what's important right now.","TWN":"但是現在重要的不是這個。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"이제 곧, 자네의 세계에도 내가 보낸 5종 침식체보다 훨씬 강력한 적들이 나타날 거야.","JPN":"もうじき、君の世界にも私が送った第5種侵食体よりも、はるかに強力な敵が現れる。","ENG":"Soon, your world will be invaded by enemies far stronger than that Category 5 C.O.","TWN":"很快，你們的世界將出現比我送過去的5類侵蝕體更加強大的敵人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"그 <color=#ffd34c>마왕</color>들이 나타난다면 자네의 세계도 우리와 같이 멸망의 길을 걷게 되겠지.","JPN":"その<color=#ffd34c>魔王</color>たちが現れたら、君の世界も我々のように滅亡の道を歩むことになるだろう。","ENG":"If the <color=#ffd34c>Demon Lords</color> appear, your world will follow the path of destruction ours did.","TWN":"那些<color=#ffd34c>魔王</color>出現時，你的世界也會像我的世界一樣踏上滅亡之路。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"멸망을 막고 싶다면, 자네는 <color=#ffd34c>준비</color>해야 하네.","JPN":"滅亡を食い止めたいなら、君は<color=#ffd34c>準備</color>をしなければならない。","ENG":"If you want to prevent the coming doom, you must be <color=#ffd34c>prepared</color>.","TWN":"如果不想滅亡，你必須進行<color=#ffd34c>準備</color>。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"이 생체 단말기에는 우리가 멸망을 막기 위해 연구했던 모든 것들의 자료가 담겨있어.","JPN":"この生体端末には我々が滅亡を防ぐために研究したすべての資料が入っている。","ENG":"This biological terminal contains all the data we've researched to stop our world from ending.","TWN":"這個生物終端機中，有我們為了抵禦滅亡研究的所有資料。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"과거의 우리가, 지금의 우리에게 모든 걸 전해주었듯이.","JPN":"過去の我々が、今の我々にすべてを伝えてくれたように。","ENG":"We're sending it to you, just as the past us sent their data.","TWN":"就像過去的我們，將所有東西傳達給現在的我們一樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"비록 우리의 준비는 미흡했고 실패했지만...... 자네가 맞게 될 운명은 우리와 달랐으면 좋겠군.","JPN":"我々の準備は不十分で失敗してしまったが……君が迎える運命は我々と違うことを祈る。","ENG":"Our preparations weren't enough, and we failed... but I hope your fate is different from ours, and the ones before us.","TWN":"雖然我們因準備不足而失敗……但我希望你即將迎來的命運與我們不同。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"그것이 우리가 최후의 최후까지도 희망을 놓치 않는 이유였으니까 말이야.","JPN":"それが、私たちが最後の最後まで希望を捨てなかった理由だから。","ENG":"That's the reason we never gave up hope, even to the very end.","TWN":"這就是我們到最後的最後，也沒有放棄希望的理由。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"그럼 행운을 비네.","JPN":"では、幸運を祈る。","ENG":"Good luck.","TWN":"那就祝你好運吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_REPLACER_RECORD_SILHOUETTE","text":{"KOREA":"부디 이번엔, 지금까지와는 다른 결과가 있기를 바라면서......","JPN":"どうか今回は、今までとは違う結果になることを願いながら……","ENG":"I pray that this time, your efforts will result in a better ending.","TWN":"希望這次，會出現迄今為止不同的結果……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_RECORD_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"부사령관님, 이건......!","JPN":"副司令官、これは……！","ENG":"Deputy Commander, this is...","TWN":"副司令官大人，這個是……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연, 제법 과격한 방법이라고 생각했는데 책임자의 얼굴을 보니 납득이 되는군요.","JPN":"なるほど、かなり過激な方法だと思っていましたが、責任者の顔を見たら納得できますね。","ENG":"Indeed. I thought it was a rather drastic way to send a gift, but I understand now that I've seen the person in charge.","TWN":"果然是這樣。雖然之前我認為這方法太過激，但看到責任者的模樣後，我突然就理解了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이건 대체 무슨 장난이지?","JPN":"これはいったい何の茶番だ？","ENG":"What sort of prank is this?","TWN":"這到底是在開什麼玩笑？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"날 가지고 노는 건가?","JPN":"私のことをバカにしてるのか！？","ENG":"Are you playing around with me?","TWN":"是在耍我嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 스스로에게 물어보시죠.","JPN":"それはみずからに問うべきでしょう。","ENG":"You should be asking that yourself.","TWN":"那個就問問你自己吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 모든 것이 다 거짓이라고 생각하나요?","JPN":"このすべてが偽りだと思っているのですか？","ENG":"Do you believe this is all a lie?","TWN":"你覺得這所有的事都是謊言嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"동력 부족.","JPN":"動力不足。","ENG":"Insufficient power.","TWN":"動力不足。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_12"},{"id":"L26_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"데이터의 누출 방지 및 보전을 위해 임시 동결 상태에 들어갑니다.","JPN":"データの漏洩防止および保全のため、臨時凍結状態に入ります。","ENG":"Entering a temporary sleep state to protect data and prevent leakage.","TWN":"為了防止資料洩露和保存，將進入臨時凍結狀態。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOK_NPC_NONAME_NULL","text":{"KOREA":"데이터 확인을 위해서는 정제된 초월 변이 인자의 공급을......","JPN":"データ確認のためには精製された超越変異ファクターの供給を……","ENG":"In order to view the data, please supply refined Transcendental Mutation Factor...","TWN":"查看資料需要提供精製的超越變異因數……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOK_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......동결이라고? 이게 어떻게 된 거지?","JPN":"……凍結だと？　どういうことだ？","ENG":"Sleep state? What just happened?","TWN":"……凍結？這是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이런 이런, 아무래도 다음 이야기를 듣고 싶으면 소녀를 위한 맛있는 스프라도 준비해야 하겠는데요?","JPN":"やれやれ、どうやら話の続きが聞きたいなら、少女のためにおいしいスープでも用意しないといけないようですね。","ENG":"Oh, my. If you want to hear more, you should prepare some delicious soup for the girl.","TWN":"這、這，看來想聽下集故事就得為少女準備美味的湯了呢？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"난 지금 농담할 기분이 아니다.","JPN":"今の私はそんな冗談に乗る気分ではない。","ENG":"I'm in no mood for a joke.","TWN":"我現在可沒心情開玩笑。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"초월 변이 인자라는 건 뭐지? 어떻게 해야 나머지 데이터를 볼 수 있나?","JPN":"超越変異ファクターというのはなんだ？　どうすれば残りのデータが見られるんだ？","ENG":"What's this Transcendental Mutation Factor? How do I see the rest of the data?","TWN":"超越變異因數又是什麼？怎樣才能查看剩下的資料呢？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 네임리스 원의 사체를 구성하는 물질일 겁니다.","JPN":"おそら、くネームレスワンの死体を構成する物質でしょう。","ENG":"It's probably the substance that makes up the Nameless One's carcass.","TWN":"可能是構成無名1屍體的物質。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 그대로 사용할 수는 없고, 분석과 가공을 거쳐야겠지만요.","JPN":"もちろんそのまま使用することはできないので、分析と加工を経なければなりません。","ENG":"Of course, it can't be used as it is. It'll need some analyzing and processing.","TWN":"肯定沒辦法直接使用，需要經過分析和加工。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"마침 저희가 가지고 있는 구 관리국의 기술들 중에 적당한 것들이 있습니다.","JPN":"ちょうど僕たちが保有している旧管理局の技術の中に、適切なものがあります。","ENG":"I happen to have some Old Administration tech that might come in handy.","TWN":"正好我們手上有適合的舊管理局技術。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"원한다면, 제가 도와드리죠. 지금까지 그래왔던 것처럼요.","JPN":"お望みなら、僕がお手伝いします。これまでのように。","ENG":"If you want, I'll help you. Like I always have.","TWN":"如果需要的話，我可以幫你們。就像一直以來那樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"......믿을 수 없는 자입니다. 부사령관님.","JPN":"……信用できない者です。副司令官。","ENG":"He can't be trusted, sir.","TWN":"……他不可信任。副司令官大人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"이런 것들을 쉽게 제공하면서도 아무 꿍꿍이가 없진 않을 겁니다.","JPN":"このようなものを気安く提供しながら、何の企みもないわけないでしょう。","ENG":"He must have an ulterior motive for giving us all this support.","TWN":"這麼簡單就將這些提供給我們，一定有別的陰謀。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"대가 없는 도움따윈 없다는 걸, 우린 지금껏 많이 겪어오지 않았습니까!","JPN":"見返りのない助けなんてないということを、私たちはこれまでたくさん経験してきたじゃないですか！","ENG":"No one offers help without wanting anything in return. We already know that!","TWN":"天下沒有免費的午餐，我們不是已經經歷很多了嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......그럴 지도 모르지.","JPN":"……そうかもしれない。","ENG":"That might be true.","TWN":"……可能是吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 난 이미 너무 많은 것을 알아버렸다.","JPN":"しかし私はあまりにも多くの真実を知ってしまった。","ENG":"But I've already learned too much.","TWN":"但我已經知道太多了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"정말 멸망이 다가오고 있다면, 여기서 멈출 수는 없어.","JPN":"本当に滅亡が近づいてきているのなら、ここで止まることはできない。","ENG":"If our world is really nearing the end, I can't stop here.","TWN":"如果真的有滅亡正在臨近，就不能停下。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아무것도 하지 않고 후회하는 것보다는 무엇이라도 시도해 봐야겠지.","JPN":"何もせず後悔するよりは、何でも試してみるべきだろう。","ENG":"I need to at least try something, rather than do nothing and regret it.","TWN":"與其最後因為什麼都不做而後悔，不如試著做些什麼。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그것이 나의 의무다.","JPN":"それが私の義務だ。","ENG":"That's my duty.","TWN":"這是我的義務。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"부사령관님......","JPN":"副司令官……","ENG":"Deputy Commander...","TWN":"副司令官大人……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"......어쩔 수 없군요.","JPN":"……仕方ありませんね。","ENG":"I guess I have no choice.","TWN":"……那就沒辦法了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"어떤 결정을 내리시건, 전 부사령관님을 따를 뿐입니다.","JPN":"どんな決断を下したとしても、私は副司令官に従うのみです。","ENG":"Whatever decision you make, I'll always follow you.","TWN":"不管您做什麼樣的決定，我都會追隨副司令官大人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"좋습니다, 거래 성립이로군요.","JPN":"いいでしょう、取引成立ですね。","ENG":"Great. We have a deal then.","TWN":"很好，交易成立。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"앞으로 잘 부탁드리죠.","JPN":"これからもよろしくお願いします。","ENG":"I'll look forward to our partnership.","TWN":"以後請多多關照。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};